const o=".menu{height:100%;width:100%;display:flex;flex-direction:column;align-items:flex-start;gap:5px;border-radius:5px;padding:6px 0;box-sizing:border-box;font-size:var(--font-d1);background-color:#fff;box-shadow:0 1px 5px #0000001a,0 1px 3px #0000001a,0 0 1px #0000001a}button{all:unset}button{width:100%;padding:10px 16px;box-sizing:border-box;white-space:nowrap;display:flex;align-items:center;gap:10px}button:hover{background-color:color-mix(in lab,var(--gray-100),white 5%)}button:active{background-color:color-mix(in lab,var(--gray-200),white 20%)}button .svg-icon{position:relative;top:.5px;width:.9em;height:.9em}.svg-icon{display:inline-flex;justify-content:center;align-items:center;width:1em;height:1em;color:currentColor;transition:transform 80ms linear;transform-origin:center}.svg-icon svg{fill:currentColor;width:100%;height:100%}";export{o as c};